defmodule DevopsAutomationWeb.CommandController do
  use DevopsAutomationWeb, :controller

  alias DevopsAutomation.CommandService

  @doc """
  POST /api/commands/execute
  Body: {"command": "disk_usage", "args": []}
  """
  def execute(conn, %{"command" => command_name} = params) do
    extra_args = Map.get(params, "args", [])

    case CommandService.execute(command_name, extra_args) do
      {:ok, result} ->
        conn
        |> put_status(:ok)
        |> json(%{status: "success", data: result})

      {:error, %{message: message} = error} ->
        conn
        |> put_status(:unprocessable_entity)
        |> json(%{status: "error", error: message, details: error})

      {:error, error} ->
        conn
        |> put_status(:unprocessable_entity)
        |> json(%{status: "error", error: error})
    end
  end

  def execute(conn, _params) do
