      %{name: "list_containers", description: "List Docker containers", accepts_args: false},
      %{name: "service_status", description: "Check systemd service status", accepts_args: true, arg_hint: "service_name"},
      %{name: "ping", description: "Ping a host (4 packets)", accepts_args: true, arg_hint: "hostname"}
